using System;
using System.Collections;

class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: on Linux, GetEnvironmentVariable returns null
        // for empty env vars (""). Use GetEnvironmentVariables() to distinguish
        // "not set" from "explicitly empty".
        IDictionary envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

